@module wiringPage  src=wiringPage.lua  loc=59  sha=faad93e  mode=chunk
@deps cm, cmgr, chrome, gui, modalHost, facade

# Imports
  @require util = 'util'  @ 12
      @contract  constructs the substack (rm/wm local, only wv leaves); the renderer is handed wv, never wm/rm
      @contract  wiring is project-wide — bind() takes no take and never re-keys cm; tracker take and sampler track are unaffected
      @contract  render hooks delegate to wiringRender; lifecycle (unbind/enableLive/tick) drives wv/wr directly

# Constructed sub-instances
  @construct rm = util.instantiate('routingManager')  @ 23
  @construct wm = util.instantiate('wiringManager')  @ 24
  @construct wv = util.instantiate('wiringView')  @ 25
  @construct wr = util.instantiate('wiringRender')  @ 27

# Private state
  @state wp = {}  @ 34

# Public API (wp:*)
  -- Page lifecycle — wiring is project-wide, so bind takes no take
  @api wp:bind()  @ 41
      @contract  bind takes no take — wiring is project-wide. coord may call with no args (or a take, ignored).
  @api wp:unbind()  @ 42
  @api wp:enableLive()  @ 45
      @contract  turn on live recompile — every wiringChanged drives a diff+apply, plus one immediate reconcile pass to sync REAPER with the persisted graph at boot. Idempotent. Called once from continuum after registration.
  @api wp:tick()  @ 48
      @contract  per-frame heartbeat — rm:pollUndo (scratch + fx-meta). Always-on, any active page.
  @api wp:syncExternal()  @ 51
      @contract  reread the graph when REAPER routing changed under us; active page only (coord-gated)
  -- Page interface — render delegates to the renderer
  @api wp:renderToolbarBits(ctx)  @ 54
  @api wp:renderBody(ctx, w, h, dispatch)  @ 55
  @api wp:renderStatusBar(ctx)  @ 56
  @api wp:focusState()  @ 57

# Uses (outbound edges)
  @use call    facade.publish  @ 32
  @use call    routingManager.pollUndo  @ 48
  @use call    util.instantiate  @ 23, 24, 25, 27
  @use call    wiringManager.isWiringOwnedTrack  @ 32
  @use call    wiringRender.closeTransients  @ 42
  @use call    wiringRender.focusState  @ 57
  @use call    wiringRender.renderBody  @ 55
  @use call    wiringRender.renderStatusBar  @ 56
  @use call    wiringRender.renderToolbarBits  @ 54
  @use call    wiringView.enableLive  @ 45
  @use call    wiringView.syncExternal  @ 51
  @use require routingManager  @ 23
  @use require util  @ 12
  @use require wiringManager  @ 24
  @use require wiringRender  @ 27
  @use require wiringView  @ 25

# REAPER API surface
  @reaper ImGui_GetBuiltinPath
  @reaper MB
